package main

import (
    "fmt"
    "log"
)

// Compliant: Extract string literals into constants
const (
    ErrInvalidUserData = "Invalid user data"
    DatabaseURL        = "postgresql://user:pass@localhost:5432/app"
    APIEndpointUsers   = "https://api.example.com/v1/users"
    ErrAPIFetchFailed  = "Failed to fetch user data from API"
)

func processUser(user *User) {
    // GOOD: Using named constants
    if user.Name == "" {
        fmt.Println(ErrInvalidUserData)
        return
    }

    if user.Email == "" {
        fmt.Println(ErrInvalidUserData)
        return
    }

    if user.Age < 0 {
        fmt.Println(ErrInvalidUserData)
        return
    }

    // GOOD: Reusable connection string
    db1 := connectDB(DatabaseURL)
    db2 := connectDB(DatabaseURL)

    // GOOD: Consistent API endpoint
    response1 := callAPI(APIEndpointUsers)
    response2 := callAPI(APIEndpointUsers)

    // GOOD: Consistent error messages
    if response1.Error != nil {
        log.Error(ErrAPIFetchFailed)
    }
    if response2.Error != nil {
        log.Error(ErrAPIFetchFailed)
    }
}

// Alternative approach: Configuration struct
type Config struct {
    DatabaseURL     string
    APIEndpoint     string
    ErrorMessages   map[string]string
}

func NewConfig() *Config {
    return &Config{
        DatabaseURL: "postgresql://user:pass@localhost:5432/app",
        APIEndpoint: "https://api.example.com/v1/users",
        ErrorMessages: map[string]string{
            "invalid_user": "Invalid user data",
            "api_failed":   "Failed to fetch user data from API",
        },
    }
}

func processUserWithConfig(user *User, config *Config) {
    // GOOD: Centralized string management
    invalidMsg := config.ErrorMessages["invalid_user"]

    if user.Name == "" || user.Email == "" || user.Age < 0 {
        fmt.Println(invalidMsg)
        return
    }

    db := connectDB(config.DatabaseURL)
    response := callAPI(config.APIEndpoint)

    if response.Error != nil {
        log.Error(config.ErrorMessages["api_failed"])
    }
}
